import {
  isProgramError,
  type Address,
  type SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM,
  type SolanaError,
} from "@solana/kit";
import { VOTING_PROGRAM_ADDRESS } from "../programs";

/** InvalidOptionIndex: Invalid option index */
export const VOTING_ERROR__INVALID_OPTION_INDEX = 0x1770; // 6000
/** AlreadyVoted: Already voted on this poll */
export const VOTING_ERROR__ALREADY_VOTED = 0x1771; // 6001
/** PollNotFound: Poll does not exist */
export const VOTING_ERROR__POLL_NOT_FOUND = 0x1772; // 6002

export type VotingError =
  | typeof VOTING_ERROR__ALREADY_VOTED
  | typeof VOTING_ERROR__INVALID_OPTION_INDEX
  | typeof VOTING_ERROR__POLL_NOT_FOUND;

let votingErrorMessages: Record<VotingError, string> | undefined;
if (process.env["NODE_ENV"] !== "production") {
  votingErrorMessages = {
    [VOTING_ERROR__ALREADY_VOTED]: `Already voted on this poll`,
    [VOTING_ERROR__INVALID_OPTION_INDEX]: `Invalid option index`,
    [VOTING_ERROR__POLL_NOT_FOUND]: `Poll does not exist`,
  };
}

export function getVotingErrorMessage(code: VotingError): string {
  if (process.env["NODE_ENV"] !== "production") {
    return (votingErrorMessages as Record<VotingError, string>)[code];
  }

  return "Error message not available in production bundles.";
}

export function isVotingError<TProgramErrorCode extends VotingError>(
  error: unknown,
  transactionMessage: {
    instructions: Record<number, { programAddress: Address }>;
  },
  code?: TProgramErrorCode,
): error is SolanaError<typeof SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM> &
  Readonly<{ context: Readonly<{ code: TProgramErrorCode }> }> {
  return isProgramError<TProgramErrorCode>(
    error,
    transactionMessage,
    VOTING_PROGRAM_ADDRESS,
    code,
  );
}
